// ============================================================
// SR SELECTOR v8 — FIXED
// - Korrekte n8n Date-Parsing (property_next_due ist ein Notion Date)
// - Case-insensitive Properties
// - Alle aktiven Pages werden genommen, auch wenn History fehlt
// - SR-fällige haben Vorrang, REST WIRD AUFGEFÜLLT
// - Debug-Output
// ============================================================

const MAX_PAGES = 10;
const QUESTIONS_PER_PAGE = 3;
const DIFFICULTY_LEVELS = ['Leicht', 'Mittel', 'Schwer', 'Experte'];

// Helper: Property finden (case-insensitive, mit/ohne property_ prefix)
function gp(json, ...names) {
  for (const name of names) {
    if (json[name] != null && json[name] !== '') return json[name];
    const pn = 'property_' + name;
    if (json[pn] != null && json[pn] !== '') return json[pn];
    const low = name.toLowerCase();
    for (const k of Object.keys(json)) {
      const kl = k.toLowerCase();
      if ((kl === low || kl === 'property_' + low) && json[k] != null && json[k] !== '') return json[k];
    }
  }
  return '';
}

// Helper: n8n Notion Date-Feld parsen
// n8n gibt Dates als String "start:2026-03-05T19:00:00.000-05:00\nend:null\ntime_zone:null"
// ODER direkt als ISO-String je nach n8n Version
function parseNotionDate(val) {
  if (!val) return null;
  const s = String(val);
  // Format: "start:2026-03-05T..."
  const startMatch = s.match(/start:([^\n]+)/);
  if (startMatch && startMatch[1] !== 'null') {
    const d = new Date(startMatch[1].trim());
    if (!isNaN(d.getTime())) return d;
  }
  // Direkter ISO-String
  const d = new Date(s);
  if (!isNaN(d.getTime())) return d;
  return null;
}

const lernItems = $('Get Lernmaterial2').all();
if (lernItems.length === 0) throw new Error('Keine aktiven Lernmaterial-Items!');

// --- History Map ---
const historyItems = $('Get Question History2').all();
const historyMap = {};
historyItems.forEach(h => {
  const j = h.json;
  const refId = gp(j, 'page_id');
  if (!refId) return;
  const reps = parseInt(gp(j, 'repetitions')) || 0;
  if (historyMap[refId] && historyMap[refId].repetitions > reps) return;

  // next_due parsen
  const nextDueRaw = gp(j, 'next_due');
  const nextDueParsed = parseNotionDate(nextDueRaw);

  historyMap[refId] = {
    ease_factor: parseFloat(gp(j, 'ease_factor')) || 2.5,
    interval: parseInt(gp(j, 'interval')) || 0,
    repetitions: reps,
    times_correct: parseInt(gp(j, 'times_correct')) || 0,
    times_incorrect: parseInt(gp(j, 'times_incorrect')) || 0,
    consecutive_correct: parseInt(gp(j, 'consecutive_correct')) || 0,
    consecutive_incorrect: parseInt(gp(j, 'consecutive_incorrect')) || 0,
    next_due: nextDueParsed,
    history_page_id: j.id || ''
  };
});

// --- Existing Questions ---
const existingQuestions = $('Get Active Questions (Existing)').all();
const existingTexts = [];
existingQuestions.forEach(q => {
  const name = (q.json.name || gp(q.json, 'Name') || '').toLowerCase().trim();
  if (name) existingTexts.push(name);
});

const now = new Date();

// --- Enrich all active Lernmaterial ---
const enriched = lernItems.map(item => {
  const j = item.json;
  const pid = j.id;
  const hist = historyMap[pid] || null;
  const hasHistory = hist !== null;

  const content = j.name || gp(j, 'Name') || '';
  const subject = gp(j, 'Subject', 'subject', 'Thema', 'thema', 'Fach', 'fach') || 'Allgemein';
  let difficulty = gp(j, 'Schwierigkeitsgrad', 'schwierigkeitsgrad', 'difficulty', 'Difficulty');
  if (!difficulty || typeof difficulty === 'number') difficulty = 'Leicht';

  // SR Werte
  const ef = hasHistory ? hist.ease_factor : 2.5;
  const interval = hasHistory ? hist.interval : 0;
  const reps = hasHistory ? hist.repetitions : 0;
  const tc = hasHistory ? hist.times_correct : 0;
  const ti = hasHistory ? hist.times_incorrect : 0;
  const cc = hasHistory ? hist.consecutive_correct : 0;
  const ci = hasHistory ? hist.consecutive_incorrect : 0;
  const hpid = hasHistory ? hist.history_page_id : '';
  const nextDue = hasHistory && hist.next_due ? hist.next_due : null;

  // Adaptive Schwierigkeit
  let idx = DIFFICULTY_LEVELS.indexOf(difficulty);
  if (idx === -1) idx = 0;
  let changed = false, reason = '';
  const tot = tc + ti;
  const acc = tot > 0 ? tc / tot : 0.5;

  if (cc >= 3 && idx < 3) {
    difficulty = DIFFICULTY_LEVELS[idx+1]; changed = true; reason = '3x richtig -> ' + difficulty;
  } else if (tot >= 5 && acc > 0.8 && idx < 3) {
    difficulty = DIFFICULTY_LEVELS[idx+1]; changed = true;
  } else if (ci >= 2 && idx > 0) {
    difficulty = DIFFICULTY_LEVELS[idx-1]; changed = true; reason = '2x falsch -> ' + difficulty;
  } else if (tot >= 5 && acc < 0.4 && idx > 0) {
    difficulty = DIFFICULTY_LEVELS[idx-1]; changed = true;
  }

  // Priority-Logik:
  // - Keine History ODER interval=0 → NEUES Thema → priority 500
  // - History mit interval>0 UND next_due <= jetzt → SR FÄLLIG → priority 2000+
  // - History mit interval>0 UND next_due > jetzt → NICHT FÄLLIG → priority -1
  let priority;
  let isNew = !hasHistory || interval === 0;
  let isOverdue = false;

  if (isNew) {
    priority = 500;
  } else if (nextDue && nextDue <= now) {
    priority = 2000 + Math.max(0, (now - nextDue) / 86400000);
    isOverdue = true;
  } else {
    priority = -1; // Nicht fällig
  }

  return {
    page_id: pid, content, subject, difficulty,
    ease_factor: ef, interval, repetitions: reps,
    times_correct: tc, times_incorrect: ti,
    consecutive_correct: cc, consecutive_incorrect: ci,
    next_due: nextDue ? nextDue.toISOString() : null,
    history_page_id: hpid,
    is_new: isNew, is_overdue: isOverdue, priority,
    accuracy_percent: Math.round(acc * 100),
    difficulty_changed: changed, difficulty_reason: reason
  };
});

// --- Sortieren & Auswählen ---
// ALLE aktiven Themen sollen Fragen bekommen!
// Reihenfolge: 1. SR-fällige (höchste Prio), 2. Neue, 3. Nicht-fällige (auffüllen)
enriched.sort((a, b) => b.priority - a.priority);

const srDue = enriched.filter(i => i.is_overdue);
const newItems = enriched.filter(i => i.is_new);
const notDue = enriched.filter(i => !i.is_overdue && !i.is_new)
  .sort((a, b) => {
    // Sortiere nicht-fällige nach nächstem Fälligkeitsdatum (bald fällige zuerst)
    const da = a.next_due ? new Date(a.next_due).getTime() : Infinity;
    const db = b.next_due ? new Date(b.next_due).getTime() : Infinity;
    return da - db;
  });

let selected = [];
// 1. SR-fällige zuerst (max 10)
selected.push(...srDue.slice(0, MAX_PAGES));
// 2. Neue Pages auffüllen
let rem = MAX_PAGES - selected.length;
if (rem > 0) selected.push(...newItems.slice(0, rem));
// 3. REST MIT NICHT-FÄLLIGEN AUFFÜLLEN — als NEUE FRAGEN (höhere Schwierigkeit!)
rem = MAX_PAGES - selected.length;
if (rem > 0) {
  // Markiere als "neue Fragen" damit OpenAI neue/schwierigere Fragen generiert
  const notDueAsNew = notDue.slice(0, rem).map(p => ({
    ...p,
    is_new: true,        // neue Fragen generieren, nicht wiederholen
    is_overdue: false     // ist KEINE SR-Wiederholung
  }));
  selected.push(...notDueAsNew);
}

if (selected.length === 0) throw new Error('Kein Lernmaterial!');

return [{
  json: {
    selected_pages: selected,
    existing_question_texts: existingTexts,
    total_pages: selected.length,
    questions_per_page: QUESTIONS_PER_PAGE,
    total_questions_expected: selected.length * QUESTIONS_PER_PAGE,
    _debug: {
      lernmaterial_total: lernItems.length,
      history_entries: historyItems.length,
      sr_due_count: srDue.length,
      new_count: newItems.length,
      not_due_count: notDue.length,
      not_due_also_selected: notDue.slice(0, MAX_PAGES).map(s => s.subject),
      selected_subjects: selected.map(s => s.subject + (s.is_overdue ? ' [SR]' : s.is_new ? ' [NEU]' : '')),
      all_subjects: enriched.map(s => s.subject + ': prio=' + s.priority)
    }
  }
}];

let raw = $json.output?.[0]?.content?.[0]?.text || '';
raw = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
let questions = [];
try { questions = JSON.parse(raw); }
catch(e) { throw new Error('JSON Parse: ' + e.message + ' | Raw: ' + raw.substring(0, 500)); }
if (!Array.isArray(questions)) throw new Error('Kein Array.');

const sel = $('SR Selector + Adaptive').first().json;
const pageMap = {};
sel.selected_pages.forEach(p => { pageMap[p.page_id] = p; });
const existingTexts = new Set((sel.existing_question_texts || []).map(t => t.toLowerCase().trim()));
const seen = new Set();
const counter = {};

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const results = [];
for (const q of questions) {
  const ql = (q.question || '').toLowerCase().trim();
  if (!ql) continue;
  let dup = existingTexts.has(ql) || seen.has(ql);
  if (!dup) { const p = ql.substring(0,50); for (const e of existingTexts) { if (e.substring(0,50)===p) { dup=true; break; } } }
  if (dup) continue;
  seen.add(ql); existingTexts.add(ql);
  const pid = q.page_id || '';
  if (!counter[pid]) counter[pid] = 0;
  if (counter[pid] >= 3) continue;
  counter[pid]++;
  const pg = pageMap[pid] || {};
  results.push({ json: {
    question: q.question, options: q.options, correct_answer: q.correct_answer,
    explanation: q.explanation || '', question_id: uuid(), question_number: counter[pid],
    page_id: pid, subject: q.subject || pg.subject || '', difficulty: pg.difficulty || 'Leicht',
    ease_factor: pg.ease_factor || 2.5, interval: pg.interval || 0,
    repetitions: pg.repetitions || 0, times_correct: pg.times_correct || 0,
    times_incorrect: pg.times_incorrect || 0,
    consecutive_correct: pg.consecutive_correct || 0, consecutive_incorrect: pg.consecutive_incorrect || 0,
    history_page_id: pg.history_page_id || '',
    is_new: pg.is_new !== false, is_overdue: pg.is_overdue || false,
    accuracy_percent: pg.accuracy_percent || 50,
    difficulty_changed: pg.difficulty_changed || false, difficulty_reason: pg.difficulty_reason || ''
  }});
}
if (results.length === 0) throw new Error('Keine Fragen!');
return results;

