const allQ = $('Parse Alle Fragen').all();
return items.map((tg, idx) => {
  const t = tg.json;
  const mid = (t.message_id || t.result?.message_id || t.messageId || '').toString();
  const sentAt = t.date ? new Date(t.date * 1000).toISOString() : new Date().toISOString();
  const q = allQ[idx]?.json || {};
  return { json: {
    question: q.question||'', question_id: q.question_id||'',
    options: Array.isArray(q.options) ? q.options.join(' | ') : (q.options||''),
    correct_answer: q.correct_answer||'', explanation: q.explanation||'',
    subject: q.subject||'', difficulty: q.difficulty||'',
    telegram_message_id: mid, sent_at: sentAt,
    ease_factor: parseFloat(q.ease_factor)||2.5, interval: parseInt(q.interval)||0,
    repetitions: parseInt(q.repetitions)||0, times_correct: parseInt(q.times_correct)||0,
    times_incorrect: parseInt(q.times_incorrect)||0,
    consecutive_correct: parseInt(q.consecutive_correct)||0,
    consecutive_incorrect: parseInt(q.consecutive_incorrect)||0,
    history_page_id: q.history_page_id||'', page_id: q.page_id||''
  }};
});
